function currencyValue(value){return Number(String(value||'0').replace(/[^0-9.-]/g,''))||0}
function reportRows(){let paid=invoices.filter(x=>x.status==='Paid'),pending=invoices.filter(x=>['Pending','Sent'].includes(x.status)),partial=invoices.filter(x=>x.status==='Partial paid'),completedAppointments=Math.max(0,appointments.length-6);return {
 'Appointment Report':[
  ['Total Appointments',appointments.length,'All scheduled appointments in the selected practice period.'],
  ['Completed Appointments',completedAppointments,'Appointments marked completed for visit documentation practice.'],
  ['Cancelled Appointments',3,'Appointments cancelled before the scheduled visit time.'],
  ['No-Show Appointments',3,'Appointments where the patient did not arrive or complete check-in.']
 ],
 'Patient Report':[
  ['Total Patients',patients.length,'All fictional patients currently stored in this training workspace.'],
  ['New Patients',patients.filter(p=>p.status==='New').length,'Patients whose status is New.'],
  ['Established Patients',patients.filter(p=>p.status==='Established'||p.status==='Complete'||p.status==='Checked in'||p.status==='In consultation').length,'Existing patients available for EHR workflow practice.'],
  ['Referral Patients',patients.filter(p=>p.status==='Referral').length,'Patients marked as Referral.'],
  ['Terminated Patients',patients.filter(p=>p.status==='Terminated').length,'Patients marked as Terminated.'],
  ['Deceased Patients',patients.filter(p=>p.status==='Deceased').length,'Patients marked as Deceased.']
 ],
 'Billing Report':[
  ['Total Invoices',invoices.length,'All invoices created in the billing practice area.'],
  ['Paid Invoices',paid.length,'Invoices marked Paid.'],
  ['Pending Invoices',pending.length,'Invoices still pending or sent to payer/patient.'],
  ['Partially Paid Invoices',partial.length,'Invoices with a partial payment recorded.'],
  ['Denied Invoices',2,'Sample denied invoices included for billing practice.'],
  ['Total Amount Collected',`$${paid.reduce((sum,x)=>sum+currencyValue(x.amount),0).toFixed(2)}`,'Total collected from invoices marked Paid.'],
  ['Outstanding Balance',`$${invoices.filter(x=>x.status!=='Paid').reduce((sum,x)=>sum+currencyValue(x.amount),0).toFixed(2)}`,'Balance remaining on invoices not fully paid.']
 ],
 'Claims Report':[
  ['Submitted Claims',28,'Claims submitted to payer queues.'],
  ['Pending Claims',9,'Claims awaiting payer response.'],
  ['Paid Claims',14,'Claims paid by the payer.'],
  ['Denied Claims',3,'Claims denied and ready for student review.'],
  ['Resubmitted Claims',2,'Corrected claims resubmitted after denial or rejection.']
 ]}}
function syncStudentReportCounts(){let rows=reportRows(),byMetric={};Object.values(rows).flat().forEach(r=>byMetric[r[0]]=r[1]);let map={reportTotalPatients:'Total Patients',reportNewPatients:'New Patients',reportEstablishedPatients:'Established Patients',reportReferralPatients:'Referral Patients',reportTerminatedPatients:'Terminated Patients',reportDeceasedPatients:'Deceased Patients',reportTotalInvoices:'Total Invoices',reportPaidInvoices:'Paid Invoices',reportPendingInvoices:'Pending Invoices',reportPartialInvoices:'Partially Paid Invoices',reportCollected:'Total Amount Collected',reportOutstanding:'Outstanding Balance'};Object.entries(map).forEach(([id,key])=>{let el=$('#'+id);if(el)el.textContent=byMetric[key]})}
function activeReportFilters(){return {date:$('#reportDateRange')?.value||'All dates',patient:$('#reportPatientName')?.value||'All patients',provider:$('#reportProvider')?.value||'All providers',status:$('#reportStatus')?.value||'All statuses'}}
let activeStudentReport='Appointment Report',activeStudentMetric='';
function showStudentReport(report,metric){activeStudentReport=report||activeStudentReport;activeStudentMetric=metric||'';syncStudentReportCounts();let filters=activeReportFilters(),rows=reportRows()[activeStudentReport]||Object.values(reportRows()).flat(),visible=activeStudentMetric?rows.filter(r=>r[0]===activeStudentMetric):rows;$('#reportActiveLabel').textContent=activeStudentMetric||activeStudentReport;$('#studentReportPreview').innerHTML=`<div class="export-note"><b>${activeStudentMetric||activeStudentReport}</b><br>Filters: ${filters.date} · ${filters.patient||'All patients'} · ${filters.provider} · ${filters.status}</div><div class="report-preview-list">${visible.map(r=>`<button type="button" class="report-preview-item" data-preview="${r[0]}"><span><b>${r[0]}</b><small>${r[2]}</small></span><b>${r[1]}</b></button>`).join('')}</div>`;$$('.report-preview-item').forEach(btn=>btn.onclick=()=>toast(`${btn.dataset.preview} selected`))}
function exportStudentReport(format){syncStudentReportCounts();let filters=activeReportFilters(),rows=Object.entries(reportRows()).flatMap(([section,items])=>items.map(r=>[section,r[0],r[1],r[2]]));if(format==='CSV/Excel'){let csv='Section,Metric,Value,Description\\n'+rows.map(r=>r.map(v=>`"${String(v).replace(/"/g,'""')}"`).join(',')).join('\\n'),blob=new Blob([csv],{type:'text/csv'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='sync2ehr-student-reports.csv';a.click();URL.revokeObjectURL(a.href);toast('CSV/Excel report exported');return}let html=`<title>Sync2EHR Student Reports</title><body style="font-family:Arial;padding:28px"><h1>Sync2EHR Student Reports</h1><p><b>Filters:</b> ${filters.date} · ${filters.patient||'All patients'} · ${filters.provider} · ${filters.status}</p>${Object.entries(reportRows()).map(([section,items])=>`<h2>${section}</h2><table border="1" cellspacing="0" cellpadding="8" style="border-collapse:collapse;width:100%">${items.map(r=>`<tr><td>${r[0]}</td><td><b>${r[1]}</b></td><td>${r[2]}</td></tr>`).join('')}</table>`).join('')}<p style="margin-top:24px">Training Mode: simulated EHR data for student practice only.</p></body>`,win=window.open('','_blank');if(win){win.document.write(html);win.document.close();win.print();toast('PDF export opened — choose Save as PDF')}else toast('Please allow pop-ups to export PDF')}
function bindStudentReports(){if(!$('#reports'))return;syncStudentReportCounts();showStudentReport('Appointment Report');$$('.student-report-card').forEach(card=>{card.querySelector('.card-head').onclick=()=>showStudentReport(card.dataset.reportType);card.querySelectorAll('button[data-report-metric]').forEach(btn=>btn.onclick=e=>{e.stopPropagation();showStudentReport(card.dataset.reportType,btn.dataset.reportMetric)})});$('#applyReportFilters')?.addEventListener('click',()=>{showStudentReport(activeStudentReport,activeStudentMetric);toast('Report filters applied')});$$('.report-export').forEach(btn=>btn.onclick=()=>exportStudentReport(btn.dataset.export))}
bindStudentReports();
function saveInvoices(){}
function normalizeBillingInvoices(){invoices=invoices.map((invoice,index)=>{let patient=patients.find(p=>p.n===invoice.patient)||{},status=invoice.status==='Partial paid'?'Partially Paid':invoice.status==='Sent'?'Pending':invoice.status||'Pending',amount=currencyValue(invoice.amount),paid=Number(invoice.amountPaid||0),payerType=invoice.payerType||(String(invoice.payer||'').toLowerCase().includes('self')?'Self-pay':'Insurance');return {...invoice,id:invoice.id||`INV-2026-${String(184+index).padStart(3,'0')}`,patient:invoice.patient||patient.n||'Unassigned patient',dob:invoice.dob||patient.dob||'',dateOfService:invoice.dateOfService||invoice.date||'Jun 18, 2026',provider:invoice.provider||'Dr. Alex Morgan',service:invoice.service||invoice.visitType||'Office visit',icd10:invoice.icd10||'Z00.00',cpt:invoice.cpt||'99213',modifier:invoice.modifier||'',payerType,payer:invoice.payer||payerType,status,amount:`$${amount.toFixed(2)}`,amountPaid:paid,remainingBalance:invoice.remainingBalance??Math.max(0,amount-paid),claimStatus:invoice.claimStatus||(payerType==='Insurance'?'Not Submitted':'N/A'),denialReason:invoice.denialReason||'',billingNotes:invoice.billingNotes||'',payments:invoice.payments||[]}})}
function billingStatusClass(status){return status==='Paid'?'green':status==='Pending'||status==='Draft'?'amber':status==='Denied'?'gray':'gray'}
function claimClass(status){return String(status||'').toLowerCase().replace(/\s+/g,'-')}
function billingPatientOptions(selected=''){return patients.map(p=>`<option value="${p.n}" data-dob="${p.dob||''}" ${p.n===selected?'selected':''}>${p.n}</option>`).join('')}
function billingForm(invoice={}){let patient=patients.find(p=>p.n===(invoice.patient||patients[0]?.n))||patients[0]||{};return `<div class="billing-modal-grid"><label>Patient Name<select name="patient" id="billingPatient" required>${billingPatientOptions(invoice.patient||patient.n)}</select></label><label>DOB<input name="dob" id="billingDob" type="date" value="${invoice.dob||patient.dob||''}" required></label><label>Date of Service<input name="dateOfService" type="date" value="${invoice.dateOfService&&invoice.dateOfService.includes('-')?invoice.dateOfService:''}" required></label><label>Provider<select name="provider"><option ${invoice.provider==='Dr. Alex Morgan'?'selected':''}>Dr. Alex Morgan</option><option ${invoice.provider==='Dr. Kim Santos'?'selected':''}>Dr. Kim Santos</option><option ${invoice.provider==='Nurse Care Team'?'selected':''}>Nurse Care Team</option></select></label><label>Service / Visit Type<input name="service" value="${invoice.service||''}" required placeholder="Follow-up visit"></label><label>ICD-10 Code<input name="icd10" value="${invoice.icd10||''}" required placeholder="Z00.00"></label><label>CPT Code<input name="cpt" value="${invoice.cpt||''}" required placeholder="99213"></label><label>Modifier, if applicable<input name="modifier" value="${invoice.modifier||''}" placeholder="25"></label><label>Payer Type<select name="payerType"><option ${invoice.payerType==='Self-pay'?'selected':''}>Self-pay</option><option ${invoice.payerType==='Insurance'?'selected':''}>Insurance</option></select></label><label>Payer<input name="payer" value="${invoice.payer||''}" required placeholder="Self-pay or payer name"></label><label>Amount<input name="amount" type="number" min="0" step="0.01" value="${currencyValue(invoice.amount)||''}" required></label><label>Payment Status<select name="status"><option ${invoice.status==='Draft'?'selected':''}>Draft</option><option ${invoice.status==='Pending'?'selected':''}>Pending</option><option ${invoice.status==='Paid'?'selected':''}>Paid</option><option ${invoice.status==='Partially Paid'?'selected':''}>Partially Paid</option><option ${invoice.status==='Denied'?'selected':''}>Denied</option></select></label><label>Claim Status<select name="claimStatus"><option ${invoice.claimStatus==='Not Submitted'?'selected':''}>Not Submitted</option><option ${invoice.claimStatus==='Submitted'?'selected':''}>Submitted</option><option ${invoice.claimStatus==='Pending'?'selected':''}>Pending</option><option ${invoice.claimStatus==='Paid'?'selected':''}>Paid</option><option ${invoice.claimStatus==='Denied'?'selected':''}>Denied</option><option ${invoice.claimStatus==='Resubmitted'?'selected':''}>Resubmitted</option></select></label><label>Denial Reason<input name="denialReason" value="${invoice.denialReason||''}" placeholder="Required if denied"></label></div><label>Billing Notes<textarea name="billingNotes" placeholder="Add coding notes, claim follow-up, or payer communication...">${invoice.billingNotes||''}</textarea></label>`}
openNewInvoice=function(){normalizeBillingInvoices();$('#modalTitle').textContent='Create invoice / billing entry';$('#modalFields').innerHTML=billingForm({dateOfService:new Date().toISOString().slice(0,10),status:'Draft',claimStatus:'Not Submitted',payerType:'Insurance'});$('#modal').dataset.type='billing-create';$('#modal').classList.remove('hidden');let select=$('#billingPatient'),dob=$('#billingDob');if(select&&dob)select.onchange=()=>{dob.value=select.selectedOptions[0].dataset.dob||''}}
function invoiceFromForm(d,existing={}){let amount=Number(d.get('amount')||0),paid=Number(existing.amountPaid||0);return {...existing,patient:d.get('patient'),dob:d.get('dob'),dateOfService:d.get('dateOfService'),provider:d.get('provider'),service:d.get('service').trim(),icd10:d.get('icd10').trim(),cpt:d.get('cpt').trim(),modifier:d.get('modifier').trim(),payerType:d.get('payerType'),payer:d.get('payer').trim(),amount:`$${amount.toFixed(2)}`,status:d.get('status'),claimStatus:d.get('claimStatus'),denialReason:d.get('denialReason').trim(),billingNotes:d.get('billingNotes').trim(),remainingBalance:Math.max(0,amount-paid)}}
renderInvoices=function(filter='All'){normalizeBillingInvoices();let list=filter==='All'?invoices:invoices.filter(x=>x.status===filter||x.claimStatus===filter);$('#invoiceList').innerHTML=`<div class="billing-table"><div class="billing-header"><span>Invoice Number</span><span>Patient Name</span><span>DOB</span><span>Date of Service</span><span>Service / Visit Type</span><span>ICD-10 / ICD-11</span><span>CPT Code</span><span>Amount</span><span>Payer</span><span>Status</span><span></span></div>${list.map(x=>`<button class="billing-row" data-invoice="${invoices.indexOf(x)}"><span><b>${x.id}</b><small>${x.claimStatus}</small></span><span>${x.patient}</span><span>${x.dob||'—'}</span><span>${x.dateOfService}</span><span>${x.service}</span><span>${x.icd10}</span><span>${x.cpt}${x.modifier?`-${x.modifier}`:''}</span><span><b>${x.amount}</b></span><span>${x.payer}</span><span><span class="pill ${billingStatusClass(x.status)}">${x.status}</span></span><span>⋯</span></button>`).join('')||'<p class="empty-state">No billing entries in this view.</p>'}</div>`;$$('.billing-row').forEach(row=>row.onclick=()=>openInvoiceDetails(invoices[row.dataset.invoice]));if(typeof syncStudentReportCounts==='function')syncStudentReportCounts()}
