function renderMedicalRecords(query=''){let medical=$('#medical');if(!medical)return;medical.innerHTML=`<div class="page-intro"><div><p class="eyebrow teal">CLINICAL DOCUMENTATION</p><h1>Medical records</h1><p>Search patients, review notes, and practice SOAP documentation.</p></div><button class="primary" id="createMedicalNote">+ Create note</button></div><div class="records-layout"><section class="card record-list"><div class="search">⌕ <input id="medicalRecordSearch" placeholder="Find a patient or SOAP note"></div><div id="medicalRecordList"></div></section><section class="card clinical-note" id="activeMedicalNote"></section></div>`;$('#createMedicalNote').onclick=()=>openMedicalNoteEditor();$('#medicalRecordSearch').value=query;$('#medicalRecordSearch').oninput=e=>renderMedicalRecordList(e.target.value);renderMedicalRecordList(query);renderActiveMedicalNote()}
function medicalNoteForm(record={}){let patient=patients.find(p=>p.n===record.patient)||patients[0]||{};return `<label>Patient<select name="patient" required>${patients.map(p=>`<option value="${p.n}" ${p.n===record.patient?'selected':''}>${p.n} · ${p.id}</option>`).join('')}</select></label><label>Note Type<select name="type"><option ${record.type==='Progress note'?'selected':''}>Progress note</option><option ${record.type==='SOAP note'?'selected':''}>SOAP note</option><option ${record.type==='Lab results'?'selected':''}>Lab results</option><option ${record.type==='Annual physical'?'selected':''}>Annual physical</option><option ${record.type==='Care plan'?'selected':''}>Care plan</option></select></label><label>Provider<input name="provider" value="${record.provider||'Dr. Alex Morgan'}" required></label><label>Check-up time<input name="checkup" type="datetime-local" value="${record.checkup||patient.checkup||''}"></label><div class="soap-form-grid"><label>Subjective<textarea name="subjective" required placeholder="Patient-reported symptoms, history, concerns...">${record.subjective||''}</textarea></label><label>Objective<textarea name="objective" required placeholder="Vitals, exam findings, lab results...">${record.objective||''}</textarea></label><label>Assessment<textarea name="assessment" required placeholder="Diagnosis, clinical impression...">${record.assessment||''}</textarea></label><label>Plan<textarea name="plan" required placeholder="Treatment, follow-up, patient education...">${record.plan||''}</textarea></label></div><label class="additional-notes-field">Additional Notes<textarea name="additionalNotes" placeholder="Extra notes, reminders, care coordination, school practice comments...">${record.additionalNotes||''}</textarea></label>`}
