function addMedicalModalExpand(){let box=$('.modal-box');if(!box)return;box.classList.remove('expanded');let old=$('#modalExpand');if(old)old.remove();let button=document.createElement('button');button.type='button';button.id='modalExpand';button.className='modal-expand';button.textContent='Expand';button.onclick=()=>{box.classList.toggle('expanded');button.textContent=box.classList.contains('expanded')?'Shrink':'Expand'};box.appendChild(button)}
