$('#modalForm').addEventListener('submit',e=>{let type=$('#modal').dataset.type;if(type!=='medical-create'&&type!=='medical-edit')return;e.preventDefault();e.stopImmediatePropagation();let d=new FormData(e.target),now=new Date(),payload={patient:d.get('patient'),type:d.get('type'),provider:d.get('provider').trim(),checkup:d.get('checkup'),subjective:d.get('subjective').trim(),objective:d.get('objective').trim(),assessment:d.get('assessment').trim(),plan:d.get('plan').trim(),additionalNotes:d.get('additionalNotes').trim(),date:'Today',time:now.toLocaleTimeString('en-US',{hour:'numeric',minute:'2-digit'})};if(type==='medical-create'){let id=`MR-${String(Date.now()).slice(-6)}`;medicalRecords.unshift({id,...payload});activeMedicalRecordId=id;toast('SOAP note created')}else{let record=medicalRecords.find(r=>r.id===$('#modal').dataset.recordId);Object.assign(record,payload);activeMedicalRecordId=record.id;toast('SOAP note updated')}let p=patients.find(x=>x.n===payload.patient);if(p&&payload.checkup){p.checkup=payload.checkup;savePatients();renderPatients()}saveMedicalRecords();renderMedicalRecords();$('#modal').classList.add('hidden');e.target.reset()},true);
