renderPrescriptions=function(tab=activeErxTab){activeErxTab=tab||activeErxTab;normalizeErxPrescriptions();let p=selectedErxPatient(),root=$('#prescriptions');if(!root)return;root.innerHTML=`<div class="page-intro"><div><p class="eyebrow teal">eRx WORKFLOW</p><h1>Prescriptions</h1><p><b>Medication Records</b> = medication list/history. <b>eRx</b> = prescription actions/workflow.</p></div><div class="erx-actions"><button class="primary" id="newPrescription">+ New Prescription</button><button class="secondary" id="requestRefill">Request Refill</button></div></div><div class="erx-banner"><div><b>Purpose</b><p>This workspace supports creating prescriptions, refill requests, pharmacy messages, and medication prior authorizations for student practice.</p></div><div class="erx-actions"><button class="filter" data-erx-quick="Medication History">Medication History</button><button class="filter" data-erx-quick="Check Interactions">Check Interactions</button></div></div>${erxPatientHeader()}<div class="erx-workflow rx-workflow"><button class="rx-workflow-card" id="createRx"><span class="rx-icon">Rx</span><div><b>New Prescription</b><small>Create and send medication orders</small></div><strong>+</strong></button><button class="rx-workflow-card" id="requestRefillCard"><span class="workflow-icon mint">↻</span><div><b>Request Refill</b><small>${refillRequests.length} refill requests</small></div><em>${refillRequests.length}</em></button><button class="rx-workflow-card" data-erx-quick="Medication History"><span class="workflow-icon blue">☰</span><div><b>Medication History</b><small>Medication list/history</small></div><strong>→</strong></button><button class="rx-workflow-card" data-erx-quick="Check Interactions"><span class="workflow-icon amber">⚠</span><div><b>Check Interactions</b><small>Run safety check</small></div><strong>✓</strong></button></div><div class="erx-subtabs">${['Prescriptions','Refill Requests','Pharmacy Messages','Prior Authorizations','Medication History'].map(t=>`<button class="${activeErxTab===t?'active':''}" data-erx-tab="${t}">${t}</button>`).join('')}</div>${erxRows()}<footer class="erx-safety"><div><span>✓</span>PDMP checked</div><div><span>✓</span>Drug allergies checked</div><div><span>✓</span>Interaction check completed</div></footer>`;bindErxEvents()}
function bindErxEvents(){$('#newPrescription').onclick=openNewPrescription;$('#createRx').onclick=openNewPrescription;$('#requestRefill').onclick=openRefillRequest;$('#requestRefillCard').onclick=openRefillRequest;$$('[data-erx-tab]').forEach(b=>b.onclick=()=>renderPrescriptions(b.dataset.erxTab));$$('[data-erx-quick]').forEach(b=>b.onclick=()=>b.dataset.erxQuick==='Medication History'?renderPrescriptions('Medication History'):toast('Safety check complete: no critical interactions found'));$$('.erx-prescription-row').forEach(row=>row.onclick=()=>openPrescriptionDetails(prescriptions[row.dataset.rx]));$$('.erx-refill-row').forEach(row=>row.onclick=()=>openErxWorkflowDetail('Refill Request',refillRequests[row.dataset.refill]));$$('.erx-message-row').forEach(row=>row.onclick=()=>openErxWorkflowDetail('Pharmacy Message',pharmacyMessages[row.dataset.message]));$$('.erx-pa-row').forEach(row=>row.onclick=()=>openErxWorkflowDetail('Prior Authorization',priorAuthorizations[row.dataset.pa]));$('#changePharmacy').onclick=openChangePharmacy;$('#changeErxPatient').onclick=openChangeErxPatient}
