function openErxWorkflowDetail(title,item){$('#modalTitle').textContent=title;$('#modalFields').innerHTML=`<div class="report-preview-list">${Object.entries(item).map(([k,v])=>`<div class="report-preview-item"><span><b>${k.replace(/([A-Z])/g,' $1').replace(/^./,c=>c.toUpperCase())}</b></span><b>${v}</b></div>`).join('')}</div><div class="billing-actions"><button type="button" class="secondary" id="markReviewed">Mark reviewed</button></div>`;$('#modal').dataset.type='details';$('#modal').classList.remove('hidden');$('#markReviewed').onclick=()=>{$('#modal').classList.add('hidden');toast(`${title} reviewed`)}}
$('#modalForm').addEventListener('submit',e=>{let type=$('#modal').dataset.type;if(!['erx-new','erx-edit','erx-refill','erx-pharmacy','erx-patient'].includes(type))return;e.preventDefault();e.stopImmediatePropagation();let d=new FormData(e.target);if(type==='erx-new'||type==='erx-edit'){let file=d.get('pdf'),rx={patient:d.get('patient'),medication:d.get('medication').trim(),directions:d.get('directions').trim(),dose:d.get('directions').trim(),quantity:d.get('quantity').trim(),refills:d.get('refills').trim(),lastFilled:d.get('lastFilled').trim()||'Today',status:d.get('status'),kind:d.get('status')==='Due for Refill'?'pending':d.get('status')==='Completed'?'history':'active',prescriber:'Dr. Alex Morgan',date:'Today',pharmacy:selectedErxPatient().preferredPharmacy||'CarePlus Pharmacy'};if(file&&file.name){rx.pdf=file.name;rx.pdfUrl=URL.createObjectURL(file)}if(type==='erx-edit'){prescriptions[Number($('#modal').dataset.rxIndex)]={...prescriptions[Number($('#modal').dataset.rxIndex)],...rx};toast('Prescription updated')}else{prescriptions.unshift(rx);toast('Prescription created')}}else if(type==='erx-refill'){refillRequests.unshift({medication:d.get('medication').trim(),patient:d.get('patient'),requestedDate:'Today',lastFilled:d.get('lastFilled').trim()||'Not listed',refillsLeft:d.get('refillsLeft'),status:d.get('status')});toast('Refill request added');activeErxTab='Refill Requests'}else if(type==='erx-pharmacy'){let p=selectedErxPatient();p.preferredPharmacy=d.get('pharmacy');savePatients();toast('Preferred pharmacy updated')}else if(type==='erx-patient'){activeErxPatient=d.get('patient');toast(`eRx patient changed to ${activeErxPatient}`)}renderPrescriptions(activeErxTab);$('#modal').classList.add('hidden');e.target.reset()},true);
