const appointmentVisitTypes=['New Patient','Follow-up','Annual Wellness','Telehealth','Medication Refill','Referral','Other'];
const appointmentStatuses=['Scheduled','Confirmed','Checked In','Completed','Cancelled','No Show','Rescheduled'];
function normalizeAppointments(){appointments.forEach((a,i)=>{if(!a.id)a.id=`APT-${String(i+1).padStart(3,'0')}`;if(!a.status)a.status='Scheduled';if(!appointmentVisitTypes.includes(a.type)){let old=a.type||'Follow-up';a.type=old.includes('Annual')?'Annual Wellness':old.includes('Telehealth')?'Telehealth':old.includes('Refill')?'Medication Refill':old.includes('Referral')?'Referral':old.includes('New')?'New Patient':'Follow-up';if(a.type==='Follow-up'&&old&&!old.includes('Follow'))a.otherType=old}if(!a.time&&a.date)a.time=a.date})}
function appointmentStatusClass(status){return String(status||'Scheduled').toLowerCase().replace(/\s+/g,'-')}
function appointmentTypeValue(formData){let type=formData.get('type');return type==='Other'?(formData.get('otherType')||'Other').trim()||'Other':type}
function appointmentForm(a={}){let selectedType=appointmentVisitTypes.includes(a.type)?a.type:(a.type?'Other':'Follow-up'),otherValue=selectedType==='Other'?(a.otherType||a.type||''):'';return `<div class="appointment-form-grid"><label>Patient<select name="name" required>${patients.map(p=>`<option value="${p.n}" ${p.n===a.patient?'selected':''}>${p.n} · ${p.id}</option>`).join('')}</select></label><label>Date & time<input name="time" type="datetime-local" value="${a.time||''}" required></label><label>Visit Type<select name="type" id="appointmentVisitType">${appointmentVisitTypes.map(t=>`<option ${selectedType===t?'selected':''}>${t}</option>`).join('')}</select></label><label>Status<select name="status">${appointmentStatuses.map(s=>`<option ${s===(a.status||'Scheduled')?'selected':''}>${s}</option>`).join('')}</select></label><label class="other-visit-field ${selectedType==='Other'?'':'hidden'}" id="otherVisitField">Other Visit Type<input name="otherType" value="${otherValue}" placeholder="Enter visit type"></label></div>`}
function bindAppointmentOtherToggle(){let select=$('#appointmentVisitType'),field=$('#otherVisitField');if(!select||!field)return;select.onchange=()=>field.classList.toggle('hidden',select.value!=='Other')}
let previousOpenModalForAppointments=openModal;openModal=function(type){if(type!=='appointment')return previousOpenModalForAppointments(type);normalizeAppointments();$('#modalTitle').textContent='Schedule appointment';$('#modalFields').innerHTML=appointmentForm({status:'Scheduled'});$('#modal').dataset.type='appointment-v2';$('#modal').classList.remove('hidden');bindAppointmentOtherToggle()}
openAppointmentEditor=function(id){normalizeAppointments();let a=appointments.find(x=>x.id===id);if(!a){toast('Appointment not found');return}$('#modalTitle').textContent=`Manage ${a.id}`;$('#modalFields').innerHTML=`<p class="form-note">Change appointment information, update status, or mark this appointment cancelled.</p>${appointmentForm(a)}<button type="button" class="danger-btn modal-cancel" id="cancelAppointment">Mark as cancelled</button>`;$('#modal').dataset.type='edit-appointment-v2';$('#modal').dataset.appointmentId=id;$('#modal').classList.remove('hidden');bindAppointmentOtherToggle();$('#cancelAppointment').onclick=()=>{a.status='Cancelled';saveAppointments();renderAppointmentList();renderCalendar();$('#modal').classList.add('hidden');toast(`${a.id} marked Cancelled`)}}
renderAppointmentList=function(){normalizeAppointments();let list=[...appointments].sort((a,b)=>(a.time||'').localeCompare(b.time||''));let target=$('#appointmentList');if(!target)return;target.innerHTML=list.map(a=>`<button class="appointment-row" data-appointment="${a.id}"><span class="appt-date">${new Date(a.time).toLocaleString([], {month:'short',day:'numeric',hour:'numeric',minute:'2-digit'})}</span><span><b>${a.patient}</b><small>${a.type}${a.otherType?` · ${a.otherType}`:''} · ${a.id}</small></span><span>${a.type}</span><span class="pill appointment-status ${appointmentStatusClass(a.status)}">${a.status}</span><span>Manage →</span></button>`).join('')||'<p class="empty-state">No upcoming appointments.</p>';$$('.appointment-row').forEach(row=>row.onclick=()=>openAppointmentEditor(row.dataset.appointment))}
$('#modalForm').addEventListener('submit',e=>{let type=$('#modal').dataset.type;if(type!=='appointment-v2'&&type!=='edit-appointment-v2')return;e.preventDefault();e.stopImmediatePropagation();let d=new FormData(e.target),visitType=appointmentTypeValue(d),other=d.get('type')==='Other'?d.get('otherType').trim():'',patient=d.get('name'),time=d.get('time'),status=d.get('status');if(type==='appointment-v2'){let id=`APT-${Date.now().toString().slice(-6)}`;appointments.push({id,patient,time,type:visitType,otherType:other,status});toast(`Appointment ${id} scheduled for ${patient}`)}else{let a=appointments.find(x=>x.id===$('#modal').dataset.appointmentId);a.patient=patient;a.time=time;a.type=visitType;a.otherType=other;a.status=status;toast(`${a.id} updated`)}let p=patients.find(x=>x.n===patient);if(p){p.checkup=time;savePatients();renderPatients()}calendarDate=new Date(time);saveAppointments();renderAppointmentList();renderCalendar();if(typeof syncStudentReportCounts==='function')syncStudentReportCounts();$('#modal').classList.add('hidden');e.target.reset()},true);
let previousAppointmentPage=page;page=function(id){previousAppointmentPage(id);if(id==='appointments'){normalizeAppointments();renderAppointmentList();renderCalendar()}}
