function savePrescriptions(){queueCloudSave()}
function cloudHeaders(extra={}){return {'apikey':SUPABASE_PUBLIC_KEY,'Authorization':`Bearer ${cloudUser?.access_token||SUPABASE_PUBLIC_KEY}`,'Content-Type':'application/json',...extra}}
async function cloudRequest(path,options={}){let response=await fetch(path,{...options,headers:{...(options.headers||{})}}),text=await response.text(),data=text?JSON.parse(text):null;if(!response.ok){let message=data?.msg||data?.message||data?.error_description||data?.error||`Supabase request failed (${response.status})`;throw new Error(message)}return data}
async function cloudSignUp(name,email,password){let data=await cloudRequest(`${SUPABASE_PROJECT_URL}/auth/v1/signup`,{method:'POST',headers:cloudHeaders(),body:JSON.stringify({email,password,data:{full_name:name}})});return data}
async function cloudSignIn(email,password){let data=await cloudRequest(`${SUPABASE_PROJECT_URL}/auth/v1/token?grant_type=password`,{method:'POST',headers:cloudHeaders(),body:JSON.stringify({email,password})});let meta=data.user?.user_metadata||{};cloudUser={access_token:data.access_token,email:data.user?.email||email,name:meta.full_name||email.split('@')[0]};cloudProfile={...cloudProfile,name:cloudUser.name,email:cloudUser.email};return {name:cloudUser.name,email:cloudUser.email}}
function cloneCloud(value){return JSON.parse(JSON.stringify(value||null))}
function storagePath(path){return String(path||'').split('/').map(encodeURIComponent).join('/')}
function safeUploadName(name){return String(name||'file').normalize('NFKD').replace(/[^\w.\-]+/g,'-').replace(/-+/g,'-').replace(/^-|-$/g,'')||'file'}
async function uploadSharedFile(file,folder){if(!cloudUser?.access_token)throw new Error('Please sign in before uploading files');if(file.size>10*1024*1024)throw new Error('The maximum upload size is 10 MB');let unique=globalThis.crypto?.randomUUID?.()||`${Date.now()}-${Math.random().toString(36).slice(2)}`,path=`${folder}/${unique}-${safeUploadName(file.name)}`;await cloudRequest(`${SUPABASE_PROJECT_URL}/storage/v1/object/${SUPABASE_UPLOAD_BUCKET}/${storagePath(path)}`,{method:'POST',headers:cloudHeaders({'Content-Type':file.type||'application/octet-stream','x-upsert':'false'}),body:file});let record={name:file.name,path,mime:file.type||'application/octet-stream',size:file.size};sharedUploadRegistry[file.name]=record;return record}
async function signedSharedFileUrl(path){let data=await cloudRequest(`${SUPABASE_PROJECT_URL}/storage/v1/object/sign/${SUPABASE_UPLOAD_BUCKET}/${storagePath(path)}`,{method:'POST',headers:cloudHeaders(),body:JSON.stringify({expiresIn:3600})}),signed=data?.signedURL||data?.signedUrl;if(!signed)throw new Error('Unable to create a secure file link');return /^https?:/i.test(signed)?signed:`${SUPABASE_PROJECT_URL}/storage/v1${signed.startsWith('/')?'':'/'}${signed}`}
async function openSharedFile(file={}){let path=sharedUploadRegistry[file.name]?.path||file.path;if(!path&&file.url){window.open(file.url,'_blank','noopener');return}if(!path){toast('The shared file is not available. Please upload it again.');return}let tab=window.open('about:blank','_blank');try{let url=await signedSharedFileUrl(path);if(tab)tab.location.href=url;else window.open(url,'_blank','noopener')}catch(error){if(tab)tab.close();toast(error.message)}}
async function deleteSharedFile(file={}){let path=sharedUploadRegistry[file.name]?.path||file.path;if(!path)return;await cloudRequest(`${SUPABASE_PROJECT_URL}/storage/v1/object/${SUPABASE_UPLOAD_BUCKET}/${storagePath(path)}`,{method:'DELETE',headers:cloudHeaders()})}
function cleanCloudFiles(list=[]){return list.map(item=>{let uploadedPdf=sharedUploadRegistry[item.pdf]||{},files=Array.isArray(item.files)?item.files.map(file=>{let uploaded=sharedUploadRegistry[file.name]||{};return {...file,path:uploaded.path||file.path||'',mime:uploaded.mime||file.mime||'',size:uploaded.size||file.size||0,url:file.url&&String(file.url).startsWith('blob:')?'':file.url}}):item.files;return {...item,url:item.url&&String(item.url).startsWith('blob:')?'':item.url,pdfPath:uploadedPdf.path||item.pdfPath||'',pdfMime:uploadedPdf.mime||item.pdfMime||'',pdfSize:uploadedPdf.size||item.pdfSize||0,pdfUrl:item.pdfUrl&&String(item.pdfUrl).startsWith('blob:')?'':item.pdfUrl,files}})}
function currentCloudState(){let profiles={...cloudProfiles};if(cloudUser?.email)profiles[cloudUser.email]=cloudProfile;return {patients:cloneCloud(cleanCloudFiles(patients)),nextPatientId,appointments:cloneCloud(appointments),prescriptions:cloneCloud(cleanCloudFiles(prescriptions)),refillRequests:cloneCloud(refillRequests),pharmacyMessages:cloneCloud(pharmacyMessages),priorAuthorizations:cloneCloud(priorAuthorizations),invoices:cloneCloud(invoices),medicalRecords:cloneCloud(medicalRecords),profiles:cloneCloud(profiles)}}
function hydratePatients(){patients.forEach((p,index)=>{if(!p.id)p.id=String(index+1).padStart(8,'0');if(!p.email)p.email=`${p.n.toLowerCase().replace(/\s+/g,'.')}@email.com`;if(!p.i)p.i=initials(p.n);if(!p.countryCode)p.countryCode='+1';if(!p.phone)p.phone=`${p.countryCode} ${p.phoneNumber||'(555) 555-0100'}`;if(!p.files)p.files=[];if(!p.checkup)p.checkup='2026-06-25T10:00'});nextPatientId=Math.max(Number(nextPatientId)||1,...patients.map(p=>Number(p.id)||0))+1}
function applyProfileToUi(){let profile=cloudProfile||{},name=profile.name||cloudUser?.name||'Alex Morgan',email=profile.email||cloudUser?.email||'alex@SynClinic.com',inputs=$$('.profile-fields input'),initial=initials(name);if($('#greetingName'))$('#greetingName').textContent=name.split(/\s+/)[0];if($('.top-actions .avatar'))$('.top-actions .avatar').textContent=initial;if($('#profileAvatar')){$('#profileAvatar').textContent=profile.photo?'':initial;$('#profileAvatar').style.backgroundImage=profile.photo?`url(${profile.photo})`:''}if(inputs[0])inputs[0].value=name;if(inputs[1]&&profile.title)inputs[1].value=profile.title;if(inputs[2])inputs[2].value=email;if(inputs[3]&&profile.phone)inputs[3].value=profile.phone}
function applyCloudState(data={}){cloudApplying=true;try{if(Array.isArray(data.patients))patients=data.patients;if(Number(data.nextPatientId))nextPatientId=Number(data.nextPatientId);hydratePatients();if(Array.isArray(data.appointments))appointments=data.appointments;if(Array.isArray(data.prescriptions))prescriptions.splice(0,prescriptions.length,...data.prescriptions);if(Array.isArray(data.refillRequests))refillRequests.splice(0,refillRequests.length,...data.refillRequests);if(Array.isArray(data.pharmacyMessages))pharmacyMessages.splice(0,pharmacyMessages.length,...data.pharmacyMessages);if(Array.isArray(data.priorAuthorizations))priorAuthorizations.splice(0,priorAuthorizations.length,...data.priorAuthorizations);if(Array.isArray(data.invoices))invoices=data.invoices;if(Array.isArray(data.medicalRecords)){medicalRecords=data.medicalRecords;activeMedicalRecordId=medicalRecords[0]?.id||activeMedicalRecordId}cloudProfiles=data.profiles||{};cloudProfile=cloudProfiles[cloudUser?.email]||cloudProfile||{};if(cloudUser){cloudProfile={name:cloudUser.name,email:cloudUser.email,...cloudProfile}}normalizeBillingInvoices();normalizeAppointments();normalizeErxPrescriptions();applyProfileToUi();syncConnectedViews()}finally{cloudApplying=false}}
async function loadCloudState({silent=false}={}){let rows=await cloudRequest(`${SUPABASE_REST_URL}/${SUPABASE_STATE_TABLE}?id=eq.${encodeURIComponent(SUPABASE_STATE_ID)}&select=data,updated_at`,{headers:cloudHeaders()});let row=Array.isArray(rows)?rows[0]:null;if(row?.data&&Object.keys(row.data).length){if(row.updated_at&&row.updated_at===cloudLastUpdated)return;cloudLastUpdated=row.updated_at||'';applyCloudState(row.data);if(!silent)toast('Shared Supabase data loaded')}else await saveCloudState(true)}
async function saveCloudState(force=false){if(!force&&(!cloudReady||cloudApplying))return;let payload={id:SUPABASE_STATE_ID,data:currentCloudState(),updated_at:new Date().toISOString()};let rows=await cloudRequest(`${SUPABASE_REST_URL}/${SUPABASE_STATE_TABLE}?on_conflict=id`,{method:'POST',headers:cloudHeaders({'Prefer':'resolution=merge-duplicates,return=representation'}),body:JSON.stringify(payload)});cloudLastUpdated=Array.isArray(rows)?rows[0]?.updated_at||payload.updated_at:payload.updated_at}
function queueCloudSave(){if(!cloudReady||cloudApplying)return;clearTimeout(cloudSaveTimer);cloudSaveTimer=setTimeout(()=>saveCloudState().catch(err=>toast(err.message)),600)}
async function bootstrapCloud(){try{await loadCloudState();cloudReady=true;if(cloudPollTimer)clearInterval(cloudPollTimer);cloudPollTimer=setInterval(()=>loadCloudState({silent:true}).catch(()=>{}),8000)}catch(error){toast(`${error.message}. Run the Supabase setup SQL first.`)}}
let syncLock=false;
function updateDashboardStats(){let cards=$$('#dashboard .stat-grid article');if(cards[0])cards[0].querySelector('strong').textContent=String(patients.length);if(cards[1])cards[1].querySelector('strong').textContent=String(appointments.length);if(cards[2]){let outstanding=invoices.filter(x=>x.status!=='Paid').reduce((sum,x)=>sum+Number(x.remainingBalance??currencyValue(x.amount)),0);cards[2].querySelector('strong').textContent=`$${outstanding.toLocaleString(undefined,{maximumFractionDigits:0})}`;cards[2].querySelector('em').textContent=`${invoices.filter(x=>x.status!=='Paid').length} invoices`}if(cards[3]){let tasks=refillRequests.filter(x=>x.status!=='Approved'&&x.status!=='Denied').length+pharmacyMessages.filter(x=>x.status!=='Closed').length+priorAuthorizations.filter(x=>!['Approved','Denied','Expired'].includes(x.status)).length;cards[3].querySelector('strong').textContent=String(tasks);cards[3].querySelector('em').textContent=`${tasks} active`}}
renderSchedule=function(){let upcoming=[...appointments].filter(a=>a.status!=='Cancelled'&&a.status!=='No Show').sort((a,b)=>(a.time||'').localeCompare(b.time||'')).slice(0,5);let target=$('#scheduleList');if(!target)return;target.innerHTML=upcoming.map((a,i)=>{let d=new Date(a.time);return `<div class="appt"><time><b>${d.toLocaleTimeString([], {hour:'numeric',minute:'2-digit'})}</b>${d.toLocaleDateString([], {month:'short',day:'numeric'})}</time><span class="line-dot ${i%3===1?'blue-dot':i%3===2?'amber-dot':''}"></span><div class="appt-info"><b>${a.patient}</b><p>${a.type}</p></div><span class="appt-tag">${a.status||'Scheduled'}</span></div>`}).join('')||'<p class="empty-state">No upcoming appointments.</p>'}
function syncConnectedViews(){if(syncLock)return;syncLock=true;try{normalizeAppointments();normalizeErxPrescriptions();updateDashboardStats();renderSchedule();let badge=$('.nav-item[data-page="appointments"] em');if(badge)badge.textContent=String(appointments.filter(a=>!['Cancelled','No Show','Completed'].includes(a.status)).length);if(typeof syncStudentReportCounts==='function')syncStudentReportCounts();let active=$('.page.active')?.id;if(active==='appointments'){renderAppointmentList();renderCalendar()}if(active==='patients')renderPatients();if(active==='billing')renderInvoices($('#invoiceFilter')?.dataset.status||'All');if(active==='medical')renderMedicalRecords($('#medicalRecordSearch')?.value||'');if(active==='prescriptions')renderPrescriptions(activeErxTab);if(active==='reports'&&typeof showStudentReport==='function')showStudentReport(activeStudentReport,activeStudentMetric)}finally{syncLock=false}}
let baseSavePatients=savePatients;savePatients=function(){baseSavePatients();syncConnectedViews();queueCloudSave()}
let baseSaveAppointments=saveAppointments;saveAppointments=function(){baseSaveAppointments();syncConnectedViews();queueCloudSave()}
let baseSaveInvoices=saveInvoices;saveInvoices=function(){baseSaveInvoices();syncConnectedViews();queueCloudSave()}
let baseSaveMedicalRecords=saveMedicalRecords;saveMedicalRecords=function(){baseSaveMedicalRecords();syncConnectedViews();queueCloudSave()}
let baseRenderPrescriptions=renderPrescriptions;renderPrescriptions=function(tab=activeErxTab){baseRenderPrescriptions(tab);savePrescriptions();updateDashboardStats()}
let basePageSync=page;page=function(id){basePageSync(id);syncConnectedViews()}
reportRows=function(){let apptCount=s=>appointments.filter(a=>a.status===s).length,paid=invoices.filter(x=>x.status==='Paid'),pending=invoices.filter(x=>['Pending','Draft'].includes(x.status)),partial=invoices.filter(x=>x.status==='Partially Paid'),denied=invoices.filter(x=>x.status==='Denied'||x.claimStatus==='Denied');return {'Appointment Report':[['Total Appointments',appointments.length,'All scheduled appointments in the selected practice period.'],['Completed Appointments',apptCount('Completed'),'Appointments marked completed for visit documentation practice.'],['Cancelled Appointments',apptCount('Cancelled'),'Appointments cancelled before the scheduled visit time.'],['No-Show Appointments',apptCount('No Show'),'Appointments where the patient did not arrive or complete check-in.']],'Patient Report':[['Total Patients',patients.length,'All fictional patients currently stored in this training workspace.'],['New Patients',patients.filter(p=>p.status==='New').length,'Patients whose status is New.'],['Established Patients',patients.filter(p=>p.status==='Established'||p.status==='Complete'||p.status==='Checked in'||p.status==='In consultation').length,'Existing patients available for EHR workflow practice.'],['Referral Patients',patients.filter(p=>p.status==='Referral').length,'Patients marked as Referral.'],['Terminated Patients',patients.filter(p=>p.status==='Terminated').length,'Patients marked as Terminated.'],['Deceased Patients',patients.filter(p=>p.status==='Deceased').length,'Patients marked as Deceased.']],'Billing Report':[['Total Invoices',invoices.length,'All invoices created in the billing practice area.'],['Paid Invoices',paid.length,'Invoices marked Paid.'],['Pending Invoices',pending.length,'Draft or pending invoices.'],['Partially Paid Invoices',partial.length,'Invoices with a partial payment recorded.'],['Denied Invoices',denied.length,'Denied invoices or denied claims ready for review.'],['Total Amount Collected',`$${paid.reduce((sum,x)=>sum+currencyValue(x.amount),0).toFixed(2)}`,'Total collected from invoices marked Paid.'],['Outstanding Balance',`$${invoices.filter(x=>x.status!=='Paid').reduce((sum,x)=>sum+Number(x.remainingBalance??currencyValue(x.amount)),0).toFixed(2)}`,'Balance remaining on invoices not fully paid.']],'Claims Report':[['Submitted Claims',invoices.filter(x=>x.claimStatus==='Submitted').length,'Claims submitted to payer queues.'],['Pending Claims',invoices.filter(x=>x.claimStatus==='Pending').length,'Claims awaiting payer response.'],['Paid Claims',invoices.filter(x=>x.claimStatus==='Paid').length,'Claims paid by the payer.'],['Denied Claims',invoices.filter(x=>x.claimStatus==='Denied').length,'Claims denied and ready for student review.'],['Resubmitted Claims',invoices.filter(x=>x.claimStatus==='Resubmitted').length,'Corrected claims resubmitted after denial or rejection.']]}}
document.addEventListener('change',async event=>{let input=event.target;if(!(input instanceof HTMLInputElement)||!['patientFile','pdf'].includes(input.name))return;let file=input.files?.[0];if(!file)return;let saveButton=$('#modalForm button[type="submit"]'),oldText=saveButton?.textContent||'Save details';if(saveButton){saveButton.disabled=true;saveButton.textContent='Uploading file...'}try{let uploaded=await uploadSharedFile(file,input.name==='pdf'?'prescriptions':'patients');input.dataset.storagePath=uploaded.path;toast(`${file.name} uploaded to shared storage`)}catch(error){input.value='';toast(error.message)}finally{if(saveButton){saveButton.disabled=false;saveButton.textContent=oldText}}});
let cloudPatientDetails=openPatientDetails;openPatientDetails=function(name){cloudPatientDetails(name);let patient=patients.find(p=>p.n===name);if(!patient)return;$$('.patient-file').forEach(button=>button.onclick=()=>openSharedFile(patient.files?.[Number(button.dataset.file)]||{}));$$('.delete-patient-file').forEach(button=>button.onclick=async()=>{let index=Number(button.dataset.file),file=patient.files?.[index];if(!file||!confirm(`Delete ${file.name}?`))return;try{await deleteSharedFile(file);patient.files.splice(index,1);savePatients();openPatientDetails(patient.n);toast('Patient document deleted from shared storage')}catch(error){toast(error.message)}})}
let cloudPrescriptionDetails=openPrescriptionDetails;openPrescriptionDetails=function(rx){cloudPrescriptionDetails(rx);let preview=$('#pdfPreview');if(preview)preview.onclick=()=>openSharedFile({name:rx.pdf,path:rx.pdfPath,url:rx.pdfUrl});let deleteButton=$('#deletePrescription');if(deleteButton)deleteButton.onclick=async()=>{if(!confirm(`Delete ${rx.medication} for ${rx.patient}?`))return;try{if(rx.pdf)await deleteSharedFile({name:rx.pdf,path:rx.pdfPath});let index=prescriptions.indexOf(rx);if(index>=0)prescriptions.splice(index,1);renderPrescriptions(activeErxTab);$('#modal').classList.add('hidden');toast('Prescription and shared file deleted')}catch(error){toast(error.message)}}}
